class Solution {
public:
    string crackSafe(int n, int k) {
        string result = "";
        vector<vector<bool>> visited(k^n, vector<bool>(1 << n, false));
        dfs(result, 0, n, k, visited);
        return result;
    }
    void dfs(string& result, int index, int n, int k, vector<vector<bool>>& visited) {
        if (index == n * k) {
            return;
        }
        for (int i = 0; i < k; ++i) {
            int state = 0;
            for (int j = 0; j < n; ++j) {
                state |= (result[index - n + j] - '0') << j;
            }
            if (!visited[i][state]) {
                visited[i][state] = true;
                result += to_string(i);
                dfs(result, index + 1, n, k, visited);
                result.pop_back();
            }
        }
    }
};
